#include <cstdio>
#include <cstdlib>
#include <cmath>
#include <omp.h>

#define BLOCK_SIZE 256

static void usage(const char *progname) {
  fprintf(stderr, "Usage: %s nx ny nt\n", progname);
  fprintf(stderr, "nx = number of points in x-dimension\n");
  fprintf(stderr, "ny = number of points in y-dimension\n");
  fprintf(stderr, "nt = number of time steps\n");
  exit(EXIT_FAILURE);
}

template <typename T>
static void print_array(T *arr, int nx, int ny) {
  for (int j = 0; j < ny; j++) {
    for (int i = 0; i < nx; i++) {
      printf("%f ", (double)arr[j * nx + i]);
    }
    printf("\n");
  }
}

template <typename T>
static void iso2dfd(T *d_out, T *d_in, int nx, int ny, int nt) {
  const int size = nx * ny;

  // Stencil coefficients for 4th order isotropic 2D FD
  const T c0 = 1.2348f;
  const T c1 = -0.1234f;

  T *d_curr = d_in;
  T *d_next = d_out;

  // Device data map
#pragma omp target data map(tofrom : d_in[0:size], d_out[0:size])
  {
    for (int t = 0; t < nt; t++) {
#pragma omp target teams distribute parallel for collapse(2) schedule(static)
      for (int j = 2; j < ny - 2; j++) {
        for (int i = 2; i < nx - 2; i++) {
          int idx = j * nx + i;
          d_next[idx] = c0 * d_curr[idx]
            + c1 * (d_curr[idx + 1] + d_curr[idx - 1] + d_curr[idx + nx] + d_curr[idx - nx]);
        }
      }
      // Swap pointers
      T *tmp = d_curr;
      d_curr = d_next;
      d_next = tmp;
    }
  }

  // If nt is even, data is in d_in, else in d_out
  if (nt % 2 == 0) {
    // Copy final data to d_out if needed
    if (d_curr != d_out) {
#pragma omp target update from(d_in[0:size])
      for (int i = 0; i < size; i++) d_out[i] = d_in[i];
    }
  } else {
    if (d_curr != d_out) {
#pragma omp target update from(d_out[0:size])
      for (int i = 0; i < size; i++) d_out[i] = d_in[i];
    }
  }
}

int main(int argc, char *argv[]) {
  if (argc != 4) {
    usage(argv[0]);
  }

  int nx = atoi(argv[1]);
  int ny = atoi(argv[2]);
  int nt = atoi(argv[3]);

  if (nx < 5 || ny < 5 || nt < 1) {
    usage(argv[0]);
  }

  const int size = nx * ny;
  float *h_in = (float *)malloc(size * sizeof(float));
  float *h_out = (float *)malloc(size * sizeof(float));

  // Initialize input data
  for (int j = 0; j < ny; j++) {
    for (int i = 0; i < nx; i++) {
      h_in[j * nx + i] = sinf(i * 0.1f) * cosf(j * 0.1f);
    }
  }

  iso2dfd<float>(h_out, h_in, nx, ny, nt);

  print_array<float>(h_out, nx, ny);

  free(h_in);
  free(h_out);

  return 0;
}
